 68→  }
 69→
 70→  await storage.initialize();
 71→
 72→  // Get config hash for evidence stamping
 73→  const snapshot = getSnapshot();
 74→  const configHash = snapshot?.configHash ?? "unknown";
 75→  const appVersion = process.env.APP_VERSION ?? "0.1.0";
