 15→/**
 16→ * Intake page — role profile intake UI with all states: Input, Loading, Preview, Confirmed, Error.
 17→ * Supports re-intake (Update Profile) from the Confirmed state.
 18→ * FR-003: Employees can generate and confirm a role profile for their tenant.
 19→ * Constitution VI: All user-facing strings are centralised in STRINGS for i18n readiness.
 20→ */
 21→
 22→"use client";
 23→
 24→import { use, useEffect, useState } from "react";
 25→
 26→// ---------------------------------------------------------------------------
 27→// String catalog — Constitution VI i18n requirement
 28→// ---------------------------------------------------------------------------
 29→
 30→const STRINGS = {
 31→  pageTitle: "Role Profile Intake",
 32→  inputLabel: "Job Description",
 33→  inputPlaceholder: "Paste your job description here (minimum 50 characters)...",
 34→  charCounter: (current: number, max: number) => `${current} / ${max} characters`,
 35→  generateButton: "Generate Profile",
 36→  generatingMessage: "Analyzing your job description...",
 37→  previewTitle: "Your Role Profile",
 38→  previewSubtitle: "Review and edit your job expectations below:",
 39→  expectationLabel: (index: number) => `Job expectation ${index + 1}`,
 40→  addExpectation: "Add Expectation",
 41→  removeExpectation: "Remove",
 42→  confirmButton: "Confirm Profile",
 43→  startOverButton: "Start Over",
 44→  confirmedTitle: "Profile Saved",
 45→  confirmedMessage: "Your role profile has been saved.",
 46→  dashboardLink: "Go to Dashboard",
 47→  errorTitle: "Something went wrong",
 48→  retryButton: "Retry",
 49→  updateProfileButton: "Update Profile",
 50→  reintakeBanner: "Your current profile will remain active until you confirm the new one.",
 51→  currentProfileTitle: "Current Profile",
 52→  newPreviewTitle: "New Profile Preview",
 53→  minExpectations: "At least 1 job expectation is required",
 54→  aiEmptyWarning:
 55→    "AI could not extract job expectations from the provided text. Please add at least one expectation manually before confirming.",
 56→  maxExpectations: "Maximum 15 job expectations allowed",
 57→  minChars: "Minimum 50 characters required",
 58→  maxChars: "Maximum 10,000 characters allowed",
 59→} as const;
 60→
 61→// ---------------------------------------------------------------------------
 62→// Constants
 63→// ---------------------------------------------------------------------------
 64→
 65→const MAX_CHARS = 10_000;
 66→const MIN_CHARS = 50;
 67→const MAX_EXPECTATIONS = 15;
 68→
 69→// ---------------------------------------------------------------------------
 70→// Types
 71→// ---------------------------------------------------------------------------
 72→
 73→type IntakeState = "loading-profile" | "input" | "loading" | "preview" | "confirmed" | "error";
 74→
 75→interface RoleProfile {
 76→  id: string;
 77→  jobExpectations: string[];
 78→  version: number;
 79→  confirmedAt: string;
 80→}
 81→
 82→// ---------------------------------------------------------------------------
 83→// Shared inline style objects
 84→// ---------------------------------------------------------------------------
 85→
 86→const containerStyle: React.CSSProperties = {
 87→  maxWidth: "800px",
 88→  margin: "2rem auto",
 89→  padding: "0 1rem",
 90→  fontFamily: "system-ui, sans-serif",
 91→};
 92→
 93→const headingStyle: React.CSSProperties = {
 94→  fontSize: "1.5rem",
 95→  fontWeight: 600,
 96→  marginBottom: "0.5rem",
 97→  color: "#111",
 98→};
 99→
100→const labelStyle: React.CSSProperties = {
101→  display: "block",
102→  fontWeight: 500,
103→  marginBottom: "0.5rem",
104→  color: "#111",
105→};
106→
107→const textareaStyle: React.CSSProperties = {
108→  width: "100%",
109→  minHeight: "180px",
110→  padding: "0.75rem",
111→  border: "1px solid #ccc",
112→  borderRadius: "4px",
113→  fontSize: "0.95rem",
114→  fontFamily: "system-ui, sans-serif",
115→  resize: "vertical",
116→  boxSizing: "border-box",
117→};
118→
119→const primaryButtonStyle: React.CSSProperties = {
120→  padding: "0.65rem 1.5rem",
121→  backgroundColor: "#1a73e8",
122→  color: "white",
123→  border: "none",
124→  borderRadius: "4px",
125→  fontSize: "0.95rem",
126→  fontWeight: 500,
127→  cursor: "pointer",
128→};
129→
130→const secondaryButtonStyle: React.CSSProperties = {
131→  padding: "0.65rem 1.5rem",
132→  backgroundColor: "#f5f5f5",
133→  color: "#111",
134→  border: "1px solid #ddd",
135→  borderRadius: "4px",
136→  fontSize: "0.95rem",
137→  fontWeight: 500,
138→  cursor: "pointer",
139→};
140→
141→const dangerButtonStyle: React.CSSProperties = {
142→  padding: "0.35rem 0.75rem",
143→  backgroundColor: "#fff",
144→  color: "#b91c1c",
145→  border: "1px solid #b91c1c",
146→  borderRadius: "4px",
147→  fontSize: "0.875rem",
148→  cursor: "pointer",
149→};
150→
151→const validationMessageStyle: React.CSSProperties = {
152→  color: "#b91c1c",
153→  fontSize: "0.875rem",
154→  marginTop: "0.4rem",
155→};
156→
157→const hintStyle: React.CSSProperties = {
158→  color: "#555",
159→  fontSize: "0.875rem",
160→  marginTop: "0.4rem",
161→};
162→
163→const sectionCardStyle: React.CSSProperties = {
164→  border: "1px solid #e0e0e0",
165→  borderRadius: "6px",
166→  padding: "1.25rem",
167→  marginBottom: "1.5rem",
168→  backgroundColor: "#fafafa",
169→};
170→
171→const expectationInputStyle: React.CSSProperties = {
172→  flex: 1,
173→  padding: "0.5rem 0.75rem",
174→  border: "1px solid #ccc",
175→  borderRadius: "4px",
176→  fontSize: "0.9rem",
177→  fontFamily: "system-ui, sans-serif",
178→};
179→
180→const bannerStyle: React.CSSProperties = {
181→  padding: "0.75rem 1rem",
182→  backgroundColor: "#fff8e1",
183→  border: "1px solid #f9a825",
184→  borderRadius: "4px",
185→  marginBottom: "1.5rem",
186→  fontSize: "0.9rem",
187→  color: "#5f4c00",
188→};
189→
190→// ---------------------------------------------------------------------------
191→// Sub-components
192→// ---------------------------------------------------------------------------
193→
194→function LoadingSpinner() {
195→  return (
196→    <span
197→      aria-hidden="true"
198→      style={{
199→        display: "inline-block",
200→        width: "16px",
201→        height: "16px",
202→        border: "2px solid rgba(255,255,255,0.4)",
203→        borderTopColor: "white",
204→        borderRadius: "50%",
205→        animation: "spin 0.7s linear infinite",
206→        verticalAlign: "middle",
207→        marginRight: "0.5rem",
208→      }}
209→    />
210→  );
211→}
212→
213→// ---------------------------------------------------------------------------
214→// Main component
215→// ---------------------------------------------------------------------------
216→
217→export default function IntakePage({ params }: { params: Promise<{ tenant: string }> }) {
218→  const { tenant } = use(params);
219→
220→  const [intakeState, setIntakeState] = useState<IntakeState>("loading-profile");
221→  const [jobText, setJobText] = useState("");
222→  const [expectations, setExpectations] = useState<string[]>([""]);
223→  const [error, setError] = useState("");
224→  const [existingProfile, setExistingProfile] = useState<RoleProfile | null>(null);
225→  const [aiReturnedEmpty, setAiReturnedEmpty] = useState(false);
226→  const [oldExpectations, setOldExpectations] = useState<string[]>([]);
227→
228→  // -------------------------------------------------------------------------
229→  // Derived validation
230→  // -------------------------------------------------------------------------
231→
232→  const charCount = jobText.length;
233→  const charCountValid = charCount >= MIN_CHARS && charCount <= MAX_CHARS;
234→  const charCountMessage =
235→    charCount < MIN_CHARS ? STRINGS.minChars : charCount > MAX_CHARS ? STRINGS.maxChars : null;
236→
237→  const expectationsValid =
238→    expectations.length >= 1 &&
239→    expectations.length <= MAX_EXPECTATIONS &&
240→    expectations.every((e) => e.trim().length > 0);
241→
242→  const expectationsCountMessage =
243→    expectations.length < 1
244→      ? STRINGS.minExpectations
245→      : expectations.length > MAX_EXPECTATIONS
246→        ? STRINGS.maxExpectations
247→        : null;
248→
249→  // -------------------------------------------------------------------------
250→  // On mount: fetch existing profile
251→  // -------------------------------------------------------------------------
252→
253→  useEffect(() => {
254→    let cancelled = false;
255→
256→    async function fetchProfile() {
257→      try {
258→        const res = await fetch(`/api/intake/${tenant}/profile`);
259→        if (cancelled) return;
260→
261→        if (res.ok) {
262→          const profile = (await res.json()) as RoleProfile;
263→          setExistingProfile(profile);
264→          setIntakeState("confirmed");
265→        } else if (res.status === 404) {
266→          setIntakeState("input");
267→        } else {
268→          setError(`Unexpected response (${res.status}). Please refresh and try again.`);
269→          setIntakeState("error");
270→        }
271→      } catch {
272→        if (!cancelled) {
273→          setError("Unable to load your profile. Please check your connection and try again.");
274→          setIntakeState("error");
275→        }
276→      }
277→    }
278→
279→    fetchProfile();
280→    return () => {
281→      cancelled = true;
282→    };
283→  }, [tenant]);
284→
285→  // -------------------------------------------------------------------------
286→  // Handlers
287→  // -------------------------------------------------------------------------
288→
289→  async function handleGenerate(e: React.FormEvent<HTMLFormElement>) {
290→    e.preventDefault();
291→    if (!charCountValid) return;
292→
293→    setIntakeState("loading");
294→    setError("");
295→
296→    try {
297→      const res = await fetch(`/api/intake/${tenant}/generate`, {
298→        method: "POST",
299→        headers: { "Content-Type": "application/json" },
300→        body: JSON.stringify({ jobText }),
301→      });
302→
303→      if (!res.ok) {
304→        const body = (await res.json().catch(() => ({}))) as { message?: string };
305→        throw new Error(body.message ?? `Server error (${res.status})`);
306→      }
307→
308→      const data = (await res.json()) as { jobExpectations: string[] };
309→      const aiEmpty = data.jobExpectations.length === 0;
310→      setAiReturnedEmpty(aiEmpty);
311→      setExpectations(aiEmpty ? [""] : data.jobExpectations);
312→      setIntakeState("preview");
313→    } catch (err) {
314→      setError(
315→        err instanceof Error ? err.message : "Failed to generate profile. Please try again.",
316→      );
317→      setIntakeState("error");
318→    }
319→  }
320→
321→  async function handleConfirm(e: React.FormEvent<HTMLFormElement>) {
322→    e.preventDefault();
323→    if (!expectationsValid) return;
324→
325→    setIntakeState("loading");
326→    setError("");
327→
328→    try {
329→      const res = await fetch(`/api/intake/${tenant}/confirm`, {
330→        method: "POST",
331→        headers: { "Content-Type": "application/json" },
332→        body: JSON.stringify({ jobExpectations: expectations.map((e) => e.trim()) }),
333→      });
334→
335→      if (!res.ok) {
336→        const body = (await res.json().catch(() => ({}))) as { message?: string };
337→        throw new Error(body.message ?? `Server error (${res.status})`);
338→      }
339→
340→      const saved = (await res.json()) as RoleProfile;
341→      setExistingProfile(saved);
342→      setOldExpectations([]);
343→      setIntakeState("confirmed");
344→    } catch (err) {
345→      setError(err instanceof Error ? err.message : "Failed to save profile. Please try again.");
346→      setIntakeState("error");
347→    }
348→  }
349→
350→  function handleStartOver() {
351→    setJobText("");
352→    setExpectations([""]);
353→    setError("");
354→    setAiReturnedEmpty(false);
355→    setOldExpectations([]);
356→    setIntakeState("input");
357→  }
358→
359→  function handleUpdateProfile() {
360→    if (existingProfile) {
361→      setOldExpectations(existingProfile.jobExpectations);
362→    }
363→    setJobText("");
364→    setExpectations([""]);
365→    setError("");
366→    setAiReturnedEmpty(false);
367→    setIntakeState("input");
368→  }
369→
370→  function handleRetry() {
371→    setError("");
372→    setIntakeState(existingProfile ? "confirmed" : "input");
373→  }
374→
375→  // Expectation list helpers
376→  function handleExpectationChange(index: number, value: string) {
377→    setExpectations((prev) => prev.map((item, i) => (i === index ? value : item)));
378→  }
379→
380→  function handleAddExpectation() {
381→    if (expectations.length >= MAX_EXPECTATIONS) return;
382→    setExpectations((prev) => [...prev, ""]);
383→  }
384→
385→  function handleRemoveExpectation(index: number) {
386→    if (expectations.length <= 1) return;
387→    setExpectations((prev) => prev.filter((_, i) => i !== index));
388→  }
389→
390→  // -------------------------------------------------------------------------
391→  // Render helpers
392→  // -------------------------------------------------------------------------
393→
394→  function renderLoadingProfile() {
395→    return (
396→      <div aria-live="polite" aria-busy="true" style={{ padding: "2rem 0", textAlign: "center" }}>
397→        <p style={{ color: "#555" }}>Loading your profile...</p>
398→      </div>
399→    );
400→  }
401→
402→  function renderInput() {
403→    return (
404→      <>
405→        {oldExpectations.length > 0 && (
406→          <div role="note" style={bannerStyle}>
407→            {STRINGS.reintakeBanner}
408→          </div>
409→        )}
410→
411→        {oldExpectations.length > 0 && (
412→          <section
413→            aria-labelledby="current-profile-heading"
414→            style={{ ...sectionCardStyle, marginBottom: "2rem" }}
415→          >
416→            <h2
417→              id="current-profile-heading"
418→              style={{ fontSize: "1rem", fontWeight: 600, marginBottom: "0.75rem" }}
419→            >
420→              {STRINGS.currentProfileTitle}
421→            </h2>
422→            <ol style={{ margin: 0, paddingLeft: "1.25rem" }}>
423→              {oldExpectations.map((exp, i) => (
424→                <li
425→                  key={`${i}-${exp}`}
426→                  style={{ marginBottom: "0.4rem", fontSize: "0.9rem", color: "#333" }}
427→                >
428→                  {exp}
429→                </li>
430→              ))}
431→            </ol>
432→          </section>
433→        )}
434→
435→        <form onSubmit={handleGenerate} noValidate aria-labelledby="input-form-heading">
436→          <h1 id="input-form-heading" style={headingStyle}>
437→            {STRINGS.pageTitle}
438→          </h1>
439→
440→          <div style={{ marginBottom: "1.5rem" }}>
441→            <label htmlFor="job-description" style={labelStyle}>
442→              {STRINGS.inputLabel}
443→            </label>
444→            <textarea
445→              id="job-description"
446→              name="jobDescription"
447→              value={jobText}
448→              onChange={(e) => setJobText(e.target.value)}
449→              placeholder={STRINGS.inputPlaceholder}
450→              maxLength={MAX_CHARS}
451→              style={{
452→                ...textareaStyle,
453→                borderColor: charCount > 0 && charCountMessage ? "#b91c1c" : "#ccc",
454→              }}
455→              aria-describedby="char-count char-validation"
456→              aria-required="true"
457→              aria-invalid={charCount > 0 && charCountMessage !== null ? "true" : "false"}
458→            />
459→            <div id="char-count" style={hintStyle}>
460→              {STRINGS.charCounter(charCount, MAX_CHARS)}
461→            </div>
462→            {charCount > 0 && charCountMessage && (
463→              <div id="char-validation" role="alert" style={validationMessageStyle}>
464→                {charCountMessage}
465→              </div>
466→            )}
467→          </div>
468→
469→          <div style={{ display: "flex", gap: "0.75rem", flexWrap: "wrap" }}>
470→            <button
471→              type="submit"
472→              disabled={!charCountValid}
473→              style={{
474→                ...primaryButtonStyle,
475→                opacity: charCountValid ? 1 : 0.6,
476→                cursor: charCountValid ? "pointer" : "not-allowed",
477→              }}
478→            >
479→              {STRINGS.generateButton}
480→            </button>
481→
482→            {oldExpectations.length > 0 && (
483→              <button type="button" onClick={handleStartOver} style={secondaryButtonStyle}>
484→                {STRINGS.startOverButton}
485→              </button>
486→            )}
487→          </div>
488→        </form>
489→      </>
490→    );
491→  }
492→
493→  function renderLoading() {
494→    return (
495→      <div aria-live="polite" aria-busy="true" style={{ padding: "2rem 0" }}>
496→        <p style={{ color: "#555", fontSize: "1rem" }}>
497→          <LoadingSpinner />
498→          {STRINGS.generatingMessage}
499→        </p>
500→        <style>{"@keyframes spin { to { transform: rotate(360deg); } }"}</style>
501→      </div>
502→    );
503→  }
504→
505→  function renderPreview() {
506→    return (
507→      <>
508→        {oldExpectations.length > 0 && (
509→          <div role="note" style={bannerStyle}>
510→            {STRINGS.reintakeBanner}
511→          </div>
512→        )}
513→
514→        {oldExpectations.length > 0 && (
515→          <section
516→            aria-labelledby="current-profile-preview-heading"
517→            style={{ ...sectionCardStyle, marginBottom: "2rem" }}
518→          >
519→            <h2
520→              id="current-profile-preview-heading"
521→              style={{ fontSize: "1rem", fontWeight: 600, marginBottom: "0.75rem" }}
522→            >
523→              {STRINGS.currentProfileTitle}
524→            </h2>
525→            <ol style={{ margin: 0, paddingLeft: "1.25rem" }}>
526→              {oldExpectations.map((exp, i) => (
527→                <li
528→                  key={`${i}-${exp}`}
529→                  style={{ marginBottom: "0.4rem", fontSize: "0.9rem", color: "#333" }}
530→                >
531→                  {exp}
532→                </li>
533→              ))}
534→            </ol>
535→          </section>
536→        )}
537→
538→        <form onSubmit={handleConfirm} noValidate aria-labelledby="preview-heading">
539→          <h1 id="preview-heading" style={headingStyle}>
540→            {oldExpectations.length > 0 ? STRINGS.newPreviewTitle : STRINGS.previewTitle}
541→          </h1>
542→          <p style={{ color: "#555", marginBottom: "1.25rem" }}>{STRINGS.previewSubtitle}</p>
543→
544→          {aiReturnedEmpty && (
545→            <div
546→              role="alert"
547→              style={{
548→                ...bannerStyle,
549→                borderColor: "#b91c1c",
550→                backgroundColor: "#fef2f2",
551→                color: "#7f1d1d",
552→              }}
553→            >
554→              {STRINGS.aiEmptyWarning}
555→            </div>
556→          )}
557→
558→          <fieldset style={{ border: "none", padding: 0, margin: "0 0 1.5rem 0" }}>
559→            <legend
560→              style={{
561→                fontWeight: 500,
562→                marginBottom: "0.75rem",
563→                fontSize: "0.95rem",
564→                color: "#111",
565→              }}
566→            >
567→              Job Expectations
568→            </legend>
569→
570→            {expectations.map((exp, index) => (
571→              <div
572→                // biome-ignore lint/suspicious/noArrayIndexKey: editable list uses index as stable key
573→                key={index}
574→                style={{
575→                  display: "flex",
576→                  gap: "0.5rem",
577→                  alignItems: "center",
578→                  marginBottom: "0.6rem",
579→                }}
580→              >
581→                <label
582→                  htmlFor={`expectation-${index}`}
583→                  style={{ ...labelStyle, margin: 0, whiteSpace: "nowrap" }}
584→                >
585→                  {STRINGS.expectationLabel(index)}
586→                </label>
587→                <input
588→                  id={`expectation-${index}`}
589→                  type="text"
590→                  value={exp}
591→                  onChange={(e) => handleExpectationChange(index, e.target.value)}
592→                  aria-required="true"
593→                  aria-label={STRINGS.expectationLabel(index)}
594→                  style={{
595→                    ...expectationInputStyle,
596→                    borderColor: exp.trim().length === 0 ? "#b91c1c" : "#ccc",
597→                  }}
598→                />
599→                {expectations.length > 1 && (
600→                  <button
601→                    type="button"
602→                    onClick={() => handleRemoveExpectation(index)}
603→                    aria-label={`${STRINGS.removeExpectation} expectation ${index + 1}`}
604→                    style={dangerButtonStyle}
605→                  >
606→                    {STRINGS.removeExpectation}
607→                  </button>
608→                )}
609→              </div>
610→            ))}
611→
612→            {expectationsCountMessage && (
613→              <div role="alert" aria-live="polite" style={validationMessageStyle}>
614→                {expectationsCountMessage}
615→              </div>
616→            )}
617→          </fieldset>
618→
619→          {expectations.length < MAX_EXPECTATIONS && (
620→            <div style={{ marginBottom: "1.5rem" }}>
621→              <button type="button" onClick={handleAddExpectation} style={secondaryButtonStyle}>
622→                {STRINGS.addExpectation}
623→              </button>
624→            </div>
625→          )}
626→
627→          <div style={{ display: "flex", gap: "0.75rem", flexWrap: "wrap" }}>
628→            <button
629→              type="submit"
630→              disabled={!expectationsValid}
631→              style={{
632→                ...primaryButtonStyle,
633→                opacity: expectationsValid ? 1 : 0.6,
634→                cursor: expectationsValid ? "pointer" : "not-allowed",
635→              }}
636→            >
637→              {STRINGS.confirmButton}
638→            </button>
639→            <button type="button" onClick={handleStartOver} style={secondaryButtonStyle}>
640→              {STRINGS.startOverButton}
641→            </button>
642→          </div>
643→        </form>
644→      </>
645→    );
646→  }
647→
648→  function renderConfirmed() {
649→    return (
650→      <section aria-labelledby="confirmed-heading">
651→        <h1 id="confirmed-heading" style={headingStyle}>
652→          {STRINGS.confirmedTitle}
653→        </h1>
654→        <p style={{ color: "#333", marginBottom: "1.5rem" }}>{STRINGS.confirmedMessage}</p>
655→
656→        {existingProfile && (
657→          <div style={sectionCardStyle}>
658→            <h2
659→              style={{ fontSize: "1rem", fontWeight: 600, marginBottom: "0.75rem", color: "#111" }}
660→            >
661→              {STRINGS.currentProfileTitle}
662→            </h2>
663→            <ol style={{ margin: 0, paddingLeft: "1.25rem" }}>
664→              {existingProfile.jobExpectations.map((exp, i) => (
665→                <li
666→                  key={`${i}-${exp}`}
667→                  style={{ marginBottom: "0.4rem", fontSize: "0.9rem", color: "#333" }}
668→                >
669→                  {exp}
670→                </li>
671→              ))}
672→            </ol>
673→          </div>
674→        )}
675→
676→        <div style={{ display: "flex", gap: "0.75rem", flexWrap: "wrap" }}>
677→          <a
678→            href={`/${tenant}/dashboard`}
679→            style={{
680→              ...primaryButtonStyle,
681→              display: "inline-block",
682→              textDecoration: "none",
683→            }}
684→          >
685→            {STRINGS.dashboardLink}
686→          </a>
687→          <button type="button" onClick={handleUpdateProfile} style={secondaryButtonStyle}>
688→            {STRINGS.updateProfileButton}
689→          </button>
690→        </div>
691→      </section>
692→    );
693→  }
694→
695→  function renderError() {
696→    return (
697→      <section aria-labelledby="error-heading" aria-live="assertive">
698→        <h1 id="error-heading" style={{ ...headingStyle, color: "#b91c1c" }}>
699→          {STRINGS.errorTitle}
700→        </h1>
701→        <p style={{ color: "#333", marginBottom: "1.5rem" }}>{error}</p>
702→        <button type="button" onClick={handleRetry} style={primaryButtonStyle}>
703→          {STRINGS.retryButton}
704→        </button>
705→      </section>
706→    );
707→  }
708→
709→  // -------------------------------------------------------------------------
710→  // Main render
711→  // -------------------------------------------------------------------------
712→
713→  return (
714→    <main style={containerStyle}>
715→      {intakeState === "loading-profile" && renderLoadingProfile()}
716→      {intakeState === "input" && renderInput()}
717→      {intakeState === "loading" && renderLoading()}
718→      {intakeState === "preview" && renderPreview()}
719→      {intakeState === "confirmed" && renderConfirmed()}
720→      {intakeState === "error" && renderError()}
721→    </main>
722→  );
723→}
